import { RunnerSize } from "../../models/runner-size";

export function getRunnerSpecForSize(size: RunnerSize): {
  minRunners: number;
  maxRunners: number;
  requestsCPU: string;
  requestsMemory: string;
  limitsCPU: string;
  limitsMemory: string;

  isAutoscalerEnabled: boolean;
  autoscalerPriority: number;
  autoscalerMinRunners: number;
} {
  switch (size) {
    case "xs":
      // Lightweight tasks (e.g. linting, simple tests)
      // Maximize parallelism with conservative resource usage
      return {
        minRunners: 8,
        maxRunners: 32,
        requestsCPU: "250m",
        requestsMemory: "512Mi",
        limitsCPU: "250m",
        limitsMemory: "1Gi",

        isAutoscalerEnabled: false,
        autoscalerPriority: 100,
        autoscalerMinRunners: 8,
      } satisfies ReturnType<typeof getRunnerSpecForSize>;
    case "sm":
      // Small builds or medium test workloads
      return {
        minRunners: 8,
        maxRunners: 16,
        requestsCPU: "1000m",
        requestsMemory: "4Gi",
        limitsCPU: "1000m",
        limitsMemory: "8Gi",

        isAutoscalerEnabled: false,
        autoscalerPriority: 200,
        autoscalerMinRunners: 6,
      } satisfies ReturnType<typeof getRunnerSpecForSize>;
    case "default":
      // Standard CI tasks — safe middle ground
      return {
        minRunners: 6,
        maxRunners: 12,
        requestsCPU: "2000m",
        requestsMemory: "8Gi",
        limitsCPU: "2000m",
        limitsMemory: "12Gi",

        isAutoscalerEnabled: false,
        autoscalerPriority: 300,
        autoscalerMinRunners: 6,
      } satisfies ReturnType<typeof getRunnerSpecForSize>;
    case "xl":
      // Heavy image builds, large monorepo installs (e.g., yarn, Docker)
      return {
        minRunners: 0,
        maxRunners: 8,
        requestsCPU: "4000m",
        requestsMemory: "8Gi",
        limitsCPU: "4000m",
        limitsMemory: "16Gi",

        isAutoscalerEnabled: false,
        autoscalerPriority: 400,
        autoscalerMinRunners: 2,
      } satisfies ReturnType<typeof getRunnerSpecForSize>;
    case "xxl":
      // Super heavy image builds, large E2E tests (e.g., yarn, Docker)
      return {
        minRunners: 0,
        maxRunners: 4,
        requestsCPU: "7000m",
        requestsMemory: "18Gi",
        limitsCPU: "7000m",
        limitsMemory: "24Gi",

        isAutoscalerEnabled: false,
        autoscalerPriority: 500,
        autoscalerMinRunners: 1,
      } satisfies ReturnType<typeof getRunnerSpecForSize>;
  }
}

