import * as k8s from "@pulumi/kubernetes";
import * as yaml from "yaml";

export function createRunnerTemplateConfigMap({
  githubAppId,
  githubAppInstallationId,
  suffix,
  installationNamespace,
  spec,
  provider,
}: {
  githubAppId: number;
  githubAppInstallationId: number;
  suffix: string;
  installationNamespace: k8s.core.v1.Namespace;
  spec: {
    minRunners: number;
    maxRunners: number;
    requestsCPU: string;
    requestsMemory: string;
    limitsCPU: string;
    limitsMemory: string;
  };
  provider: k8s.Provider;
}) {
  return new k8s.core.v1.ConfigMap(`runner-config-${githubAppId}-${githubAppInstallationId}${suffix}`, {
    metadata: {
      namespace: installationNamespace.metadata.name,
    },
    data: {
      "runner-template.yaml": yaml.stringify({
        spec: {
          containers: [
            {
              name: "$job",
              resources: {
                requests: {
                  cpu: spec.requestsCPU,
                  memory: spec.requestsMemory,
                },
                limits: {
                  cpu: spec.limitsCPU,
                  memory: spec.limitsMemory,
                },
              },
            },
          ],
        },
      }),
    },
  }, { provider });
}

import * as k8s from "@pulumi/kubernetes";
import * as pulumi from "@pulumi/pulumi";
import { createRunnerRole } from "../kubernetes-scaleset/createRunnerRole";
import { createRunnerRoleBinding } from "../kubernetes-scaleset/createRunnerRoleBinding";
import { createRunnerServiceAccount } from "../kubernetes-scaleset/createRunnerServiceAccount";
import { getRunnerSpecForSize } from "../kubernetes-scaleset/getRunnerSpecForSize";
import { createAndroidRunnerTemplateConfigMap } from "./createAndroidRunnerTemplateConfigMap";

/**
 * Create a specialized runner scale set for Android jobs.
 *
 * This scale set includes an Android emulator sidecar container with KVM access,
 * allowing each runner pod to have its own isolated emulator instance for parallel
 * jobs. It also includes a dedicated Android emulator service that can be used to
 * start and stop the emulator instances.
 */
export function createAndroidRunnerScaleSet({
  githubAppId,
  githubAppInstallationId,
  githubAppUrl,
  githubAppPrivateKey,
  installationNamespace,
  controllerServiceAccount,
  provider,
}: {
  githubAppId: number;
  githubAppInstallationId: number;
  githubAppUrl: string;
  githubAppPrivateKey: string;
  installationNamespace: k8s.core.v1.Namespace;
  controllerServiceAccount: {
    namespace: pulumi.Input<string>;
    name: pulumi.Input<string>;
  };
  provider: k8s.Provider;
}) {
  const suffix = "-android";
  const spec = {
    minRunners: 1,
    maxRunners: 1,
    requestsCPU: "1000m",
    requestsMemory: "4Gi",
    limitsCPU: "2000m",
    limitsMemory: "8Gi",
    isAutoscalerEnabled: false,
    autoscalerPriority: 0,
    autoscalerMinRunners: 0,
  } satisfies ReturnType<typeof getRunnerSpecForSize>;

  const runnerTemplateConfigMap = createAndroidRunnerTemplateConfigMap({
    githubAppId,
    githubAppInstallationId,
    suffix,
    installationNamespace,
    spec,
    provider,
  });
  const runnerServiceAccount = createRunnerServiceAccount({
    githubAppId,
    githubAppInstallationId,
    suffix,
    installationNamespace,
    provider,
  });
  const runnerRole = createRunnerRole({
    githubAppId,
    githubAppInstallationId,
    suffix,
    installationNamespace,
    provider,
  });
  createRunnerRoleBinding({
    githubAppId,
    githubAppInstallationId,
    suffix,
    installationNamespace,
    runnerServiceAccount,
    runnerRole,
    provider,
  });

  new k8s.helm.v4.Chart(`github-arc-scale-set-${githubAppId}-${githubAppInstallationId}${suffix}`, {
    chart: "oci://ghcr.io/actions/actions-runner-controller-charts/gha-runner-scale-set",
    // renovate: datasource="docker" image="ghcr.io/actions/gha-runner-scale-set-controller"
    version: "0.13.1",
    namespace: installationNamespace.metadata.name,
    values: {
      githubConfigUrl: githubAppUrl,
      githubConfigSecret: {
        github_app_id: githubAppId.toString(),
        github_app_installation_id: githubAppInstallationId.toString(),
        github_app_private_key: githubAppPrivateKey,
      },
      maxRunners: spec.maxRunners,
      minRunners: spec.minRunners,

      runnerGroup: "default",
      runnerScaleSetName: `k8s-ci-android`,

      labels: {
        "github.com/app-id": githubAppId.toString(),
        "github.com/installation-id": githubAppInstallationId.toString(),
        "github.com/trusted-runner": "false",
      },
      annotations: {
        "kula.app/gha-runner-autoscaler-enabled": "false",
        "kula.app/gha-runner-autoscaler-cpu": spec.limitsCPU,
        "kula.app/gha-runner-autoscaler-memory": spec.limitsMemory,
        "kula.app/gha-runner-autoscaler-priority": "350",
        "kula.app/gha-runner-autoscaler-min-runners": "1",
      },

      // Configure the listener container to use the Kubernetes mode
      listenerTemplate: {
        metadata: {
          annotations: {
            "prometheus.io/scrape": "true",
            "prometheus.io/port": "8080",
            "prometheus.io/path": "/metrics",
          },
        },
        spec: {
          tolerations: [
            {
              key: "node-role.kubernetes.io/control-plane",
              operator: "Exists",
              effect: "NoSchedule",
            },
            {
              key: "node-role.kubernetes.io/master",
              operator: "Exists",
              effect: "NoSchedule",
            },
            {
              key: "node-role.kubernetes.io/etcd",
              operator: "Exists",
              effect: "NoSchedule",
            },
          ],
          containers: [
            {
              name: "listener",
              resources: {
                requests: {
                  cpu: "50m",
                  memory: "64Mi",
                },
                limits: {
                  cpu: "200m",
                  memory: "256Mi",
                },
              },
            },
          ],
        },
      },

      // Expose listener metrics for monitoring and demand-aware autoscaling
      listenerMetrics: {
        counters: {
          gha_started_jobs_total: {
            labels: ["repository", "organization", "enterprise", "job_name", "event_name"],
          },
          gha_completed_jobs_total: {
            labels: ["repository", "organization", "enterprise", "job_name", "event_name", "job_result"],
          },
        },
        gauges: {
          gha_assigned_jobs: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_running_jobs: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_registered_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_busy_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_min_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_max_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_desired_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_idle_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
        },
        histograms: {
          gha_job_startup_duration_seconds: {
            labels: ["repository", "organization", "enterprise", "job_name", "event_name"],
            buckets: [5, 10, 30, 60, 120, 300, 600, 1800, 3600],
          },
        },
      },

      // Configure the runner container to use the Kubernetes mode
      containerMode: {
        type: "kubernetes",
        kubernetesModeWorkVolumeClaim: {
          accessModes: ["ReadWriteOnce"],
          storageClassName: "local-path",
          resources: {
            requests: {
              storage: "16Gi",
            },
          },
        } as k8s.types.input.core.v1.PersistentVolumeClaim,
      },
      template: {
        spec: {
          tolerations: [
            {
              key: "node-role.kubernetes.io/control-plane",
              operator: "Exists",
              effect: "NoSchedule",
            },
            {
              key: "node-role.kubernetes.io/master",
              operator: "Exists",
              effect: "NoSchedule",
            },
            {
              key: "node-role.kubernetes.io/etcd",
              operator: "Exists",
              effect: "NoSchedule",
            },
          ],
          containers: [
            // Runner container
            {
              name: "runner",
              // renovate: datasource="docker" image="ghcr.io/actions/actions-runner"
              image: "ghcr.io/actions/actions-runner:2.331.0",
              command: ["/home/runner/run.sh"],
              env: [
                {
                  name: "ACTIONS_RUNNER_CONTAINER_HOOKS",
                  value: "/home/runner/k8s/index.js",
                },
                {
                  name: "ACTIONS_RUNNER_POD_NAME",
                  valueFrom: {
                    fieldRef: {
                      fieldPath: "metadata.name",
                    },
                  },
                },
                {
                  name: "ACTIONS_RUNNER_REQUIRE_JOB_CONTAINER",
                  value: "true",
                },
                {
                  name: "ACTIONS_RUNNER_CONTAINER_HOOK_TEMPLATE",
                  value: "/etc/config/runner-template.yaml",
                },
                {
                  name: "ACTIONS_RUNNER_USE_KUBE_SCHEDULER",
                  value: "true",
                },
              ],
              volumeMounts: [
                {
                  name: "work",
                  mountPath: "/home/runner/_work",
                },
                {
                  name: "hook-template",
                  mountPath: "/etc/config",
                },
              ],
              securityContext: {
                runAsNonRoot: true,
                runAsUser: 1001,
                allowPrivilegeEscalation: false,
                readOnlyRootFilesystem: false,
                seccompProfile: {
                  type: "RuntimeDefault",
                },
                capabilities: {
                  drop: ["ALL"],
                },
              },
            },
          ],
          securityContext: {
            runAsNonRoot: true,
            runAsUser: 1001,
            runAsGroup: 123,
            fsGroup: 123,
            seccompProfile: {
              type: "RuntimeDefault",
            },
          },
          serviceAccountName: runnerServiceAccount.metadata.name,
          volumes: [
            {
              name: "hook-template",
              configMap: {
                name: runnerTemplateConfigMap.metadata.name,
              },
            },
          ],
        },
      },
      controllerServiceAccount: {
        namespace: controllerServiceAccount.namespace,
        name: controllerServiceAccount.name,
      },
      rbac: {
        create: false,
        serviceAccount: {
          create: false,
          name: runnerServiceAccount.metadata.name,
        },
      },
    },
  }, { provider });
}

import * as k8s from "@pulumi/kubernetes";
import * as pulumi from "@pulumi/pulumi";
import { RunnerSize } from "../../models/runner-size";
import { createRunnerRole } from "./createRunnerRole";
import { createRunnerRoleBinding } from "./createRunnerRoleBinding";
import { createRunnerServiceAccount } from "./createRunnerServiceAccount";
import { createRunnerTemplateConfigMap } from "./createRunnerTemplateConfigMap";
import { getRunnerSpecForSize } from "./getRunnerSpecForSize";

/**
 * Create the runner scale set in the installation namespace
 */
export function createKubernetesRunnerScaleSet({
  githubAppId,
  githubAppInstallationId,
  githubAppUrl,
  githubAppPrivateKey,
  installationNamespace,
  size,
  controllerServiceAccount,
  provider,
}: {
  githubAppId: number;
  githubAppInstallationId: number;
  githubAppUrl: string;
  githubAppPrivateKey: string;
  installationNamespace: k8s.core.v1.Namespace;
  size: RunnerSize;
  controllerServiceAccount: {
    namespace: pulumi.Input<string>;
    name: pulumi.Input<string>;
  };
  provider: k8s.Provider;
}) {
  let suffix = size !== "default" ? `-${size}` : "";
  const spec = getRunnerSpecForSize(size);

  const runnerTemplateConfigMap = createRunnerTemplateConfigMap({
    githubAppId,
    githubAppInstallationId,
    suffix,
    installationNamespace,
    spec,
    provider,
  });
  const runnerServiceAccount = createRunnerServiceAccount({
    githubAppId,
    githubAppInstallationId,
    suffix,
    installationNamespace,
    provider,
  });
  const runnerRole = createRunnerRole({
    githubAppId,
    githubAppInstallationId,
    suffix,
    installationNamespace,
    provider,
  });
  createRunnerRoleBinding({
    githubAppId,
    githubAppInstallationId,
    suffix,
    installationNamespace,
    runnerServiceAccount,
    runnerRole,
    provider,
  });

  new k8s.helm.v4.Chart(`github-arc-scale-set-${githubAppId}-${githubAppInstallationId}${suffix}`, {
    chart: "oci://ghcr.io/actions/actions-runner-controller-charts/gha-runner-scale-set",
    // renovate: datasource="docker" image="ghcr.io/actions/gha-runner-scale-set-controller"
    version: "0.13.1",
    namespace: installationNamespace.metadata.name,
    values: {
      githubConfigUrl: githubAppUrl,
      githubConfigSecret: {
        github_app_id: githubAppId.toString(),
        github_app_installation_id: githubAppInstallationId.toString(),
        github_app_private_key: githubAppPrivateKey,
      },
      // Only set maxRunners if autoscaler is disabled to avoid SSA field conflicts
      // When autoscaler is enabled, it manages maxRunners based on annotations
      ...(spec.isAutoscalerEnabled ? {} : { maxRunners: spec.maxRunners }),
      minRunners: spec.minRunners,

      runnerGroup: "default",
      runnerScaleSetName: `k8s-ci-default${suffix}`,

      labels: {
        "github.com/app-id": githubAppId.toString(),
        "github.com/installation-id": githubAppInstallationId.toString(),
        "github.com/trusted-runner": "false",
      },
      annotations: {
        "kula.app/gha-runner-autoscaler-enabled": spec.isAutoscalerEnabled ? "true" : "false",
        "kula.app/gha-runner-autoscaler-cpu": spec.limitsCPU,
        "kula.app/gha-runner-autoscaler-memory": spec.limitsMemory,
        "kula.app/gha-runner-autoscaler-priority": spec.autoscalerPriority.toString(),
        "kula.app/gha-runner-autoscaler-min-runners": spec.autoscalerMinRunners.toString(),
      },

      // Configure the listener container to use the Kubernetes mode
      listenerTemplate: {
        metadata: {
          annotations: {
            "prometheus.io/scrape": "true",
            "prometheus.io/port": "8080",
            "prometheus.io/path": "/metrics",
          },
        },
        spec: {
          // Allow listener scheduling on any node, including control-plane nodes
          tolerations: [
            {
              key: "node-role.kubernetes.io/control-plane",
              operator: "Exists",
              effect: "NoSchedule",
            },
            {
              key: "node-role.kubernetes.io/master",
              operator: "Exists",
              effect: "NoSchedule",
            },
            {
              key: "node-role.kubernetes.io/etcd",
              operator: "Exists",
              effect: "NoSchedule",
            },
          ],
          containers: [
            {
              name: "listener",
              resources: {
                requests: {
                  cpu: "50m",
                  memory: "64Mi",
                },
                limits: {
                  cpu: "200m",
                  memory: "256Mi",
                },
              },
            },
          ],
        },
      },

      // Expose listener metrics for monitoring and demand-aware autoscaling
      listenerMetrics: {
        counters: {
          gha_started_jobs_total: {
            labels: ["repository", "organization", "enterprise", "job_name", "event_name"],
          },
          gha_completed_jobs_total: {
            labels: ["repository", "organization", "enterprise", "job_name", "event_name", "job_result"],
          },
        },
        gauges: {
          gha_assigned_jobs: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_running_jobs: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_registered_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_busy_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_min_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_max_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_desired_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_idle_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
        },
        histograms: {
          gha_job_startup_duration_seconds: {
            labels: ["repository", "organization", "enterprise", "job_name", "event_name"],
            buckets: [5, 10, 30, 60, 120, 300, 600, 1800, 3600],
          },
        },
      },

      // Configure the runner container to use the Kubernetes mode
      containerMode: {
        type: "kubernetes",
        kubernetesModeWorkVolumeClaim: {
          accessModes: ["ReadWriteOnce"],
          // We are deploying the runner in a single node cluster, so we can use the local-path storage class
          storageClassName: "local-path",
          resources: {
            requests: {
              storage: "16Gi",
            },
          },
        } as k8s.types.input.core.v1.PersistentVolumeClaim,
      },
      template: {
        spec: {
          // Allow scheduling on any node, including control-plane nodes
          tolerations: [
            {
              key: "node-role.kubernetes.io/control-plane",
              operator: "Exists",
              effect: "NoSchedule",
            },
            {
              key: "node-role.kubernetes.io/master",
              operator: "Exists",
