import * as k8s from "@pulumi/kubernetes";
import * as pulumi from "@pulumi/pulumi";
import { RunnerSize } from "../../models/runner-size";
import { createRoleBinding } from "./createRoleBinding";
import { createRunnerRole } from "./createRunnerRole";
import { createRunnerServiceAccount } from "./createRunnerServiceAccount";
import { getRunnerSpecForSize } from "./getRunnerSpecForSize";

/**
 * Create a Docker-in-Docker runner scale set in the installation namespace
 * This is used to run the runner in a Docker container
 */
export function createDockerInDockerScaleSet({
  githubAppId,
  githubAppInstallationId,
  githubAppUrl,
  githubAppPrivateKey,
  installationNamespace,
  registryMirrorUrl,
  size,
  controllerServiceAccount,
  provider,
}: {
  githubAppId: number;
  githubAppInstallationId: number;
  githubAppUrl: string;
  githubAppPrivateKey: string;
  installationNamespace: k8s.core.v1.Namespace;
  registryMirrorUrl: pulumi.Input<string>;
  size: RunnerSize;
  controllerServiceAccount: {
    namespace: pulumi.Input<string>;
    name: pulumi.Input<string>;
  };
  provider: k8s.Provider;
}) {
  let suffix = size !== "default" ? `-${size}` : "";
  const spec = getRunnerSpecForSize(size);

  const runnerServiceAccount = createRunnerServiceAccount({
    githubAppId,
    githubAppInstallationId,
    suffix,
    installationNamespace,
    provider,
  });
  const runnerRole = createRunnerRole({
    githubAppId,
    githubAppInstallationId,
    suffix,
    installationNamespace,
    provider,
  });
  createRoleBinding({
    githubAppId,
    githubAppInstallationId,
    suffix,
    installationNamespace,
    runnerServiceAccount,
    runnerRole,
    provider,
  });

  new k8s.helm.v4.Chart(`github-arc-scale-set-${githubAppId}-${githubAppInstallationId}-dind${suffix}`, {
    chart: "oci://ghcr.io/actions/actions-runner-controller-charts/gha-runner-scale-set",
    // renovate: datasource="docker" image="ghcr.io/actions/gha-runner-scale-set-controller"
    version: "0.13.1",
    namespace: installationNamespace.metadata.name,
    values: {
      githubConfigUrl: githubAppUrl,
      githubConfigSecret: {
        github_app_id: githubAppId.toString(),
        github_app_installation_id: githubAppInstallationId.toString(),
        github_app_private_key: githubAppPrivateKey,
      },
      // Only set maxRunners if autoscaler is disabled to avoid SSA field conflicts
      // When autoscaler is enabled, it manages maxRunners based on annotations
      ...(spec.isAutoscalerEnabled ? {} : { maxRunners: spec.maxRunners }),
      minRunners: spec.minRunners,

      runnerGroup: "default",
      runnerScaleSetName: `k8s-ci-dind${suffix}`,

      labels: {
        "github.com/app-id": githubAppId.toString(),
        "github.com/installation-id": githubAppInstallationId.toString(),
        "github.com/trusted-runner": "false",
      },
      annotations: {
        "kula.app/gha-runner-autoscaler-enabled": spec.isAutoscalerEnabled ? "true" : "false",
        "kula.app/gha-runner-autoscaler-cpu": spec.limitsCPU,
        "kula.app/gha-runner-autoscaler-memory": spec.limitsMemory,
        "kula.app/gha-runner-autoscaler-priority": spec.autoscalerPriority.toString(),
        "kula.app/gha-runner-autoscaler-min-runners": spec.autoscalerMinRunners.toString(),
      },

      // Configure the listener container to use the Kubernetes mode
      listenerTemplate: {
        metadata: {
          annotations: {
            "prometheus.io/scrape": "true",
            "prometheus.io/port": "8080",
            "prometheus.io/path": "/metrics",
          },
        },
        spec: {
          // Allow listener scheduling on any node, including control-plane nodes
          tolerations: [
            {
              key: "node-role.kubernetes.io/control-plane",
              operator: "Exists",
              effect: "NoSchedule",
            },
            {
              key: "node-role.kubernetes.io/master",
              operator: "Exists",
              effect: "NoSchedule",
            },
            {
              key: "node-role.kubernetes.io/etcd",
              operator: "Exists",
              effect: "NoSchedule",
            },
          ],
          containers: [
            {
              name: "listener",
              resources: {
                requests: {
                  cpu: "50m",
                  memory: "64Mi",
                },
                limits: {
                  cpu: "200m",
                  memory: "256Mi",
                },
              },
            },
          ],
        },
      },

      // Expose listener metrics for monitoring and demand-aware autoscaling
      listenerMetrics: {
        counters: {
          gha_started_jobs_total: {
            labels: ["repository", "organization", "enterprise", "job_name", "event_name"],
          },
          gha_completed_jobs_total: {
            labels: ["repository", "organization", "enterprise", "job_name", "event_name", "job_result"],
          },
        },
        gauges: {
          gha_assigned_jobs: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_running_jobs: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_registered_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_busy_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_min_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_max_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_desired_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
          gha_idle_runners: {
            labels: ["name", "namespace", "repository", "organization", "enterprise"],
          },
        },
        histograms: {
          gha_job_startup_duration_seconds: {
            labels: ["repository", "organization", "enterprise", "job_name", "event_name"],
            buckets: [5, 10, 30, 60, 120, 300, 600, 1800, 3600],
          },
        },
      },

      // Configure the runner container to use the Docker-in-Docker mode
      containerMode: {
        // Set the container mode to none to avoid the default implementation of `dind`
        type: "none",
      },
      template: {
        spec: {
          // Allow scheduling on any node, including control-plane nodes
          tolerations: [
            {
              key: "node-role.kubernetes.io/control-plane",
              operator: "Exists",
              effect: "NoSchedule",
            },
            {
              key: "node-role.kubernetes.io/master",
              operator: "Exists",
              effect: "NoSchedule",
            },
            {
              key: "node-role.kubernetes.io/etcd",
              operator: "Exists",
              effect: "NoSchedule",
            },
          ],
          containers: [
            {
              name: "runner",
              // renovate: datasource="docker" image="ghcr.io/actions/actions-runner"
              image: "ghcr.io/actions/actions-runner:2.331.0",
              securityContext: {
                allowPrivilegeEscalation: false,
                readOnlyRootFilesystem: false, // GitHub runner needs to write files
                runAsNonRoot: true,
                runAsUser: 1001, // Non-root user
                seccompProfile: {
                  type: "RuntimeDefault",
                },
                capabilities: {
                  drop: ["ALL"], // Drop all capabilities
                },
              },
              command: ["/home/runner/run.sh"],
              env: [
                {
                  name: "DOCKER_HOST",
                  value: "unix:///run/docker/docker.sock",
                },
                {
                  name: "RUNNER_WAIT_FOR_DOCKER_IN_SECONDS",
                  value: "120",
                },
              ],
              volumeMounts: [
                {
                  name: "work",
                  mountPath: "/home/runner/_work",
                },
                {
                  name: "dind-sock",
                  mountPath: "/run/docker",
                  readOnly: true,
                },
              ],
              // resources: resourcesRequirements,
            },
            {
              name: "dind",
              // renovate: datasource="docker" image="docker:dind"
              image: "docker:29.2.1-dind",
              // References for chosen arguments:
              // - https://github.com/actions/actions-runner-controller/issues/3691#issuecomment-2298125942
              args: [
                "dockerd",
                "--host=unix:///run/docker/docker.sock",
                "--group=$(DOCKER_GROUP_GID)",
                "--mtu=1400",
                "--default-network-opt=bridge=com.docker.network.driver.mtu=1400",
                "--storage-driver=overlay2", // Use overlay2 for better performance
                "--experimental", // Enable experimental features for better build cache
                // Registry mirror configuration - primary caching mechanism
                pulumi.interpolate`--registry-mirror=${registryMirrorUrl}`,
                pulumi.interpolate`--insecure-registry=${registryMirrorUrl}`.apply((url) =>
                  url.replace(/https?:\/\//, "")
                ),
                // Additional registry mirror optimizations
                "--max-concurrent-downloads=10", // Increase concurrent downloads
                "--max-concurrent-uploads=5", // Increase concurrent uploads
              ],
              env: [
                {
                  name: "DOCKER_GROUP_GID",
                  value: "123",
                },
                {
                  name: "DOCKER_BUILDKIT",
                  value: "1", // Enable BuildKit for better caching
                },
                {
                  name: "BUILDKIT_INLINE_CACHE",
                  value: "1", // Enable inline cache for BuildKit
                },
              ],
              securityContext: {
                privileged: true, // Required for DinD - cannot be avoided
                // allowPrivilegeEscalation: removed - conflicts with privileged: true
                readOnlyRootFilesystem: false, // DinD needs to write to filesystem
                runAsNonRoot: false, // DinD must run as root
                seccompProfile: {
                  type: "RuntimeDefault", // Apply default seccomp profile
                },
              },
              volumeMounts: [
                {
                  name: "work",
                  mountPath: "/home/runner/_work",
                },
                {
                  name: "dind-sock",
                  mountPath: "/run/docker",
                },
                {
                  name: "dind-externals",
                  mountPath: "/home/runner/externals",
                },
              ],
              resources: {
                requests: {
                  cpu: spec.requestsCPU,
                  memory: spec.requestsMemory,
                },
                limits: {
                  cpu: spec.limitsCPU,
                  memory: spec.limitsMemory,
                },
              },
            },
          ],
          initContainers: [
            {
              args: ["-r", "-v", "/home/runner/externals/.", "/home/runner/tmpDir/"],
              command: ["cp"],
              // renovate: datasource="docker" image="ghcr.io/actions/actions-runner"
              image: "ghcr.io/actions/actions-runner:2.331.0",
              name: "init-dind-externals",
              securityContext: {
                allowPrivilegeEscalation: false,
                readOnlyRootFilesystem: false, // Needs to copy files
                runAsNonRoot: true,
                runAsUser: 1001, // Non-root user
                seccompProfile: {
                  type: "RuntimeDefault",
                },
                capabilities: {
                  drop: ["ALL"], // Drop all capabilities
                },
              },
              volumeMounts: [
                {
                  mountPath: "/home/runner/tmpDir",
                  name: "dind-externals",
                },
              ],
            },
          ],
          serviceAccountName: runnerServiceAccount.metadata.name,
          volumes: [
            {
              name: "dind-sock",
              emptyDir: {},
            },
            {
              name: "dind-externals",
              emptyDir: {},
            },
            {
              name: "work",
              emptyDir: {},
            },
          ],
        },
      },
      controllerServiceAccount: {
        namespace: controllerServiceAccount.namespace,
        name: controllerServiceAccount.name,
      },
      rbac: {
        create: false,
        serviceAccount: {
          create: false,
          name: runnerServiceAccount.metadata.name,
        },
      },
    },
  }, { provider });
}

