import * as k8s from "@pulumi/kubernetes";
import * as yaml from "yaml";

/**
 * Create a runner template config map for Android jobs with emulator sidecar.
 *
 * The template includes an Android emulator as a sidecar container with KVM
 * device access, making it accessible at localhost:5555 from job containers.
 */
export function createAndroidRunnerTemplateConfigMap({
  githubAppId,
  githubAppInstallationId,
  suffix,
  installationNamespace,
  spec,
  provider,
}: {
  githubAppId: number;
  githubAppInstallationId: number;
  suffix: string;
  installationNamespace: k8s.core.v1.Namespace;
  spec: {
    minRunners: number;
    maxRunners: number;
    requestsCPU: string;
    requestsMemory: string;
    limitsCPU: string;
    limitsMemory: string;
  };
  provider: k8s.Provider;
}) {
  return new k8s.core.v1.ConfigMap(`runner-config-${githubAppId}-${githubAppInstallationId}${suffix}`, {
    metadata: {
      namespace: installationNamespace.metadata.name,
    },
    data: {
      "runner-template.yaml": yaml.stringify({
        spec: {
          containers: [
            {
              name: "$job",
              resources: {
                requests: {
                  cpu: spec.requestsCPU,
                  memory: spec.requestsMemory,
                },
                limits: {
                  cpu: spec.limitsCPU,
                  memory: spec.limitsMemory,
                },
              },
            },
            // Android emulator sidecar accessible at localhost:5555
            {
              name: "android-emulator",
              image: "us-docker.pkg.dev/android-emulator-268719/images/30-google-x64:latest",
              ports: [
                {
                  containerPort: 5555,
                  name: "adb",
                },
              ],
              securityContext: {
                privileged: true,
              },
              resources: {
                requests: {
                  cpu: "1",
                  memory: "4Gi",
                },
                limits: {
                  cpu: "2",
                  memory: "8Gi",
                },
              },
              volumeMounts: [
                {
                  name: "kvm",
                  mountPath: "/dev/kvm",
                },
              ],
            },
          ],
          volumes: [
            {
              name: "kvm",
              hostPath: {
                path: "/dev/kvm",
                type: "CharDevice",
              },
            },
          ],
        },
      }),
    },
  }, { provider });
}

